/** @type {Array<{id: number, name: string, price: number, inventory: number, status: string}>} */
let products = [
  { id: 1, name: 'Laptop', price: 999, inventory: 50, status: 'active' },
  { id: 2, name: 'Phone', price: 699, inventory: 120, status: 'active' },
  { id: 3, name: 'Tablet', price: 499, inventory: 30, status: 'active' },
  { id: 4, name: 'Headphones', price: 199, inventory: 200, status: 'active' },
  { id: 5, name: 'Watch', price: 299, inventory: 75, status: 'active' }
];

/** @type {string|null} */
let lastSyncedAt = null;

/**
 * Returns all products from the catalog.
 * Simulates a 100ms database read.
 */
export async function getAllProducts() {
  await new Promise(resolve => setTimeout(resolve, 100));
  return products.map(p => ({ ...p }));
}

/**
 * Returns the ISO timestamp of the last successful sync.
 */
export async function getLastSyncedAt() {
  return lastSyncedAt;
}

/**
 * Simulates syncing product data from an upstream ERP/PIM system.
 * Introduces realistic changes: price adjustments, inventory corrections,
 * and occasional status updates — as an upstream sync would.
 */
export async function syncProducts() {
  // Simulate the latency of a real upstream sync (anywhere from 200ms–2s)
  await new Promise(resolve => setTimeout(resolve, 200 + Math.random() * 800));

  products = products.map(p => {
    // Random price fluctuation (-5 to +15)
    const priceDelta = Math.floor(Math.random() * 21) - 5;
    // Random inventory adjustment (-3 to +8)
    const inventoryDelta = Math.floor(Math.random() * 12) - 3;

    return {
      ...p,
      price: Math.max(1, p.price + priceDelta),
      inventory: Math.max(0, p.inventory + inventoryDelta),
      status: Math.random() < 0.05 ? 'discontinued' : p.status
    };
  });

  lastSyncedAt = new Date().toISOString();
}

import type { Metadata } from 'next';

export const metadata: Metadata = {
  title: 'Admin',
  description: 'E-commerce administration panel'
};

export default function AdminLayout({
  children
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <div style={{ maxWidth: 960, margin: '0 auto', padding: '0 16px' }}>
      <nav
        style={{
          display: 'flex',
          gap: 24,
          alignItems: 'center',
          padding: '12px 0',
          borderBottom: '1px solid #ddd',
          marginBottom: 24
        }}
      >
        <strong style={{ fontSize: 18 }}>Admin</strong>
        <a
          href="/admin/catalog"
          style={{ color: '#0066cc', textDecoration: 'none' }}
        >
          Catalog
        </a>
      </nav>
      {children}
    </div>
  );
}

import { unstable_cache } from 'next/cache';
import { revalidateTag } from 'next/cache';
import { getAllProducts, syncProducts, getLastSyncedAt } from '@/lib/db';

// ---------------------------------------------------------------------------
// Cached data helpers
// ---------------------------------------------------------------------------

const getCachedProducts = unstable_cache(
  async () => getAllProducts(),
  ['products'],
  { tags: ['products'] }
);

const getCachedLastSyncedAt = unstable_cache(
  async () => getLastSyncedAt(),
  ['products-last-synced'],
  { tags: ['products'] }
);

// ---------------------------------------------------------------------------
// Page
// ---------------------------------------------------------------------------

export default async function AdminCatalogPage() {
  // ---- inline Server Action ------------------------------------------------
  async function syncCatalog() {
    'use server';

    // 1. Refresh data from the upstream ERP/PIM
    await syncProducts();

    // 2. Invalidate all cached data tagged "products" so the next page
    //    render picks up the fresh data across any view that shares the tag
    revalidateTag('products');
  }

  // ---- render -------------------------------------------------------------
  const products = await getCachedProducts();
  const lastSynced = await getCachedLastSyncedAt();
  const productCount = products.length;

  return (
    <div>
      <h1 style={{ marginTop: 0, marginBottom: 8 }}>Product Catalog</h1>

      {/* Sync form — a regular HTML <form> that invokes the inline Server Action */}
      <form action={syncCatalog}>
        <p style={{ color: '#555', fontSize: 14, marginBottom: 16 }}>
          {lastSynced ? (
            <>
              Last synced:{' '}
              <time dateTime={lastSynced}>
                {new Date(lastSynced).toLocaleString()}
              </time>
            </>
          ) : (
            <>No sync has been run yet.</>
          )}
          &ensp;·&ensp;
          {productCount} product{productCount === 1 ? '' : 's'}
        </p>

        <button
          type="submit"
          style={{
            padding: '8px 20px',
            fontSize: 14,
            fontWeight: 600,
            color: '#fff',
            background: '#0066cc',
            border: 'none',
            borderRadius: 4,
            cursor: 'pointer',
            marginBottom: 24
          }}
        >
          Sync latest catalog
        </button>
      </form>

      {/* Product table */}
      <div style={{ overflowX: 'auto' }}>
        <table
          style={{
            width: '100%',
            borderCollapse: 'collapse',
            fontSize: 14
          }}
        >
          <thead>
            <tr style={{ textAlign: 'left', borderBottom: '2px solid #ddd' }}>
              <th style={{ padding: '8px 12px' }}>ID</th>
              <th style={{ padding: '8px 12px' }}>Name</th>
              <th style={{ padding: '8px 12px' }}>Price</th>
              <th style={{ padding: '8px 12px' }}>Inventory</th>
              <th style={{ padding: '8px 12px' }}>Status</th>
            </tr>
          </thead>
          <tbody>
            {products.map((product) => (
              <tr
                key={product.id}
                style={{
                  borderBottom: '1px solid #eee'
                }}
              >
                <td style={{ padding: '8px 12px' }}>{product.id}</td>
                <td style={{ padding: '8px 12px', fontWeight: 500 }}>
                  {product.name}
                </td>
                <td style={{ padding: '8px 12px' }}>
                  ${product.price.toLocaleString()}
                </td>
                <td style={{ padding: '8px 12px' }}>
                  {product.inventory.toLocaleString()}
                </td>
                <td style={{ padding: '8px 12px' }}>
                  <span
                    style={{
                      display: 'inline-block',
                      padding: '2px 8px',
                      borderRadius: 4,
                      fontSize: 12,
                      fontWeight: 600,
                      textTransform: 'uppercase',
                      color:
                        product.status === 'active' ? '#1a7f37' : '#a00',
                      background:
                        product.status === 'active'
                          ? '#dafbe1'
                          : '#ffebe9'
                    }}
                  >
                    {product.status}
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

